html, body { margin: 0px; padding: 0px; background: white; }
* { box-sizing: border-box; }
html, body { margin: 0px; padding: 0px; font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif; color: rgb(26, 26, 26); background: rgb(250, 250, 250); }
.page { min-height: 800px; display: flex; flex-direction: column; }
.nav { display: flex; gap: 20px; align-items: center; padding: 16px 32px; background: white; border-bottom: 1px solid rgb(234, 234, 234); }
.nav a { color: rgb(68, 68, 68); text-decoration: none; font-size: 14px; }
.nav a:hover { color: rgb(0, 112, 243); }
.nav .brand { font-weight: 700; font-size: 18px; color: rgb(26, 26, 26); margin-right: auto; }
.main { flex: 1 1 0%; padding: 48px 32px; max-width: 960px; width: 100%; margin: 0px auto; }
.main h1 { font-size: 36px; margin: 0px 0px 16px; }
.main h2 { font-size: 22px; margin: 0px; }
.main .lead { font-size: 18px; color: rgb(85, 85, 85); margin-bottom: 32px; }
.card-grid { display: grid; grid-template-columns: repeat(3, 1fr); gap: 16px; }
.card { background: white; border: 1px solid rgb(234, 234, 234); border-radius: 8px; padding: 24px; }
.card h3 { margin: 0px 0px 8px; font-size: 16px; }
.card p { margin: 0px; color: rgb(102, 102, 102); font-size: 14px; }
.tbl { width: 100%; border-collapse: collapse; background: white; border: 1px solid rgb(234, 234, 234); border-radius: 8px; overflow: hidden; }
.tbl th, .tbl td { padding: 12px 16px; text-align: left; }
.tbl thead { background: rgb(244, 244, 244); font-size: 12px; text-transform: uppercase; letter-spacing: 0.5px; color: rgb(85, 85, 85); }
.tbl tbody tr { border-top: 1px solid rgb(234, 234, 234); }
.profile { display: flex; gap: 20px; align-items: center; background: white; padding: 24px; border: 1px solid rgb(234, 234, 234); border-radius: 8px; }
.avatar { width: 64px; height: 64px; border-radius: 50%; background: linear-gradient(135deg, rgb(110, 142, 251), rgb(167, 119, 227)); color: white; font-size: 24px; font-weight: 700; display: grid; place-items: center; }
.dim { color: rgb(136, 136, 136); }
.footer { padding: 16px 32px; color: rgb(136, 136, 136); font-size: 12px; border-top: 1px solid rgb(234, 234, 234); background: white; }
.longread { max-width: 720px; margin: 0px auto; font-family: Georgia, "Times New Roman", serif; color: rgb(26, 26, 26); }
.longread h1, .longread h2, .longread h3, .longread h4 { font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif; letter-spacing: -0.01em; }
