.longread h1 { font-size: 44px; line-height: 1.15; margin: 0px 0px 18px; }
.longread h2 { font-size: 26px; line-height: 1.3; margin: 56px 0px 14px; }
.longread h3 { font-size: 19px; line-height: 1.4; margin: 36px 0px 10px; }
.longread h4 { font-size: 15px; margin: 0px 0px 8px; }
.lr-lede { font-size: 22px; line-height: 1.55; color: rgb(42, 42, 42); font-style: italic; margin: 0px 0px 24px; }
